    } else {
        /* Handle control actions */

        /* SAFE_IDLE: Always stay in safe idle - no action needed */
        if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_SAFE_IDLE;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
            output.changed = true;
        }

        /* FILTERING: Filter is on, waiting for clear turbidity samples */
        else if (controller->state == CONTROLLER_STATE_FILTERING) {
            /* Count clear streaks while level >= 40 and turbidity <= 35 */
            int current_turbidity = controller->last_turbidity_ntu;
            int current_level = controller->last_level;

            if (current_turbidity > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                /* Turbidity too high - reset clear streak */
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
                output.changed = true;
            } else if (current_level < CONTROLLER_COMPLETE_LEVEL) {
                /* Level too low - still filtering */
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_SETTLING;
                output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
                output.changed = true;
            } else if (current_level >= CONTROLLER_COMPLETE_LEVEL) {
                /* Clear streak achieved - check for settling */
                int clear_streak = controller->clear_streak_count;
                if (clear_streak >= CONTROLLER_CLEAR_STREAK_REQUIRED && current_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Check if we've been settling long enough */
                    uint32_t settle_duration_ms = input.now_ms - controller->settling_started_ms;
                    if (settle_duration_ms >= CONTROLLER_SETTLING_MS) {
                        output.filter_on = false;
                        output.drain_open = true; /* Open drain for draining */
                        output.state = CONTROLLER_STATE_DRAINING;
                        output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                        output.changed = true;
                    } else {
                        /* Settling in progress - stay in FILTERING state but filter is on to reduce turbidity */
                        output.filter_on = true;
                        output.drain_open = false;
                        output.state = CONTROLLER_STATE_FILTERING;
                        output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                        output.changed = true;
                    }
                } else {
                    /* Not enough clear streaks - stay in FILTERING state */
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = true;
                }
            } else {
                /* Level too low - still filtering */
                output.filter_on = true;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                output.changed = true;
            }
        }

        /* SETTLING: Filter is off, drain closed, waiting for clear streaks */
        else if (controller->state == CONTROLLER_STATE_SETTLING) {
            /* Turbidity > 40 resets clear streak and returns to FILTERING */
            int current_turbidity = controller->last_turbidity_ntu;

            if (current_turbidity > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                output.filter_on = true;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                output.changed = true;
            } else {
                /* Valid clear turbidity - drain open after 400ms settling */
                uint32_t settle_duration_ms = input.now_ms - controller->settling_started_ms;
                if (settle_duration_ms >= CONTROLLER_SETTLING_MS) {
                    output.filter_on = false;
                    output.drain_open = true; /* Open drain for draining */
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                    output.changed = true;
                } else {
                    /* Still settling - filter is off, drain closed */
                    output.filter_on = false;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_SETTLING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
                    output.changed = true;
                }
            }
        }

        /* DRAINING: Drain is open, waiting for disturbances */
        else if (controller->state == CONTROLLER_STATE_DRAINING) {
            int current_turbidity = controller->last_turbidity_ntu;

            /* Turbidity > 50 and level >= 40 closes drain, turns filter on, resets streak */
            if (current_turbidity > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU && current_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                output.filter_on = true;
                output.drain_open = false; /* Close drain */
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                output.changed = true;
            } else if (current_turbidity <= CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
                /* Valid turbidity - drain stays open */
                output.filter_on = false;
                output.drain_open = true;
                output.state = CONTROLLER_STATE_DRAINING;
                output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                output.changed = true;
            } else {
                /* Unknown turbidity - drain stays open */
                output.filter_on = false;
                output.drain_open = true;
                output.state = CONTROLLER_STATE_DRAINING;
                output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                output.changed = true;
            }
        }

        /* COMPLETE: Level below minimum drain threshold */
        else if (controller->state == CONTROLLER_STATE_COMPLETE) {
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_SAFE_IDLE;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
            output.changed = true;
        }

        /* UNKNOWN STATE - go to safe idle */
        else {
            controller_set_safe_idle(controller);
        }
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
        return "STATE SAFE_IDLE";
    default:
        return "STATE UNKNOWN";
    }
}

#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Parse the input line */
    char *buffer = NULL;

    if (input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY) {
        buffer = "INVALID TURBIDITY";
    } else {
        buffer = NULL;
    }

    /* Check for malformed input - invalid characters or line too long */
    size_t len = strlen(buffer);
    if (len > PROTOCOL_MAX_LINE_LENGTH) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
    }

    /* Parse the line */
    uint8_t parsed_kind = PROTOCOL_PARSE_IGNORED;
    int turbidity_ntu = 0;
    int level = 0;

    if (buffer != NULL) {
        size_t pos = 0;

        if (buffer[0] == 'S' && buffer[1] == 'E') {
            /* SENSE <TURB/LEVEL> */
            if (pos + 5 <= len && buffer[pos + 3] == ' ') {
                parsed_kind = PROTOCOL_PARSE_TURBIDITY;
                pos += 4;
                while (pos + 6 <= len && buffer[pos + 5] != '\0') {
                    if (buffer[pos + 5] == ' ') {
                        break;
                    }
                    pos++;
                }
                turbidity_ntu = atoi(buffer + pos);
            } else if (pos + 5 <= len && buffer[pos + 3] == ' ') {
                parsed_kind = PROTOCOL_PARSE_LEVEL;
                pos += 4;
                while (pos + 7 <= len && buffer[pos + 6] != '\0') {
                    if (buffer[pos + 6] == ' ') {
                        break;
                    }
                    pos++;
                }
                level = atoi(buffer + pos);
            } else {
                parsed_kind = PROTOCOL_PARSE_INVALID_TURBIDITY;
                turbidity_ntu = -1;
            }
        } else if (buffer[0] == 'S' && buffer[1] == 'E') {
            /* SENSE <TURB/LEVEL> */
            size_t pos = 0;

            if (pos + 5 <= len && buffer[pos + 3] == ' ') {
                parsed_kind = PROTOCOL_PARSE_TURBIDITY;
                pos += 4;
                while (pos + 6 <= len && buffer[pos + 5] != '\0') {
                    if (buffer[pos + 5] == ' ') {
                        break;
                    }
                    pos++;
                }
                turbidity_ntu = atoi(buffer + pos);
            } else if (pos + 5 <= len && buffer[pos + 3] == ' ') {
                parsed_kind = PROTOCOL_PARSE_LEVEL;
                pos += 4;
                while (pos + 7 <= len && buffer[pos + 6] != '\0') {
                    if (buffer[pos + 6] == ' ') {
                        break;
                    }
                    pos++;
                }
                level = atoi(buffer + pos);
            } else {
                parsed_kind = PROTOCOL_PARSE_INVALID_TURBIDITY;
                turbidity_ntu = -1;
            }
        } else {
            parsed_kind = PROTOCOL_PARSE_SENSOR_TIMEOUT;
            turbidity_ntu = 0;
            level = CONTROLLER_MIN_PROCESS_LEVEL;
        }
    }

    /* Check if we got valid sensor data */
    bool has_valid_turbidity = (input.kind == CONTROLLER_INPUT_TURBIDITY && parsed_kind == PROTOCOL_PARSE_TURBIDITY && turbidity_ntu >= 0);
    bool has_valid_level = (input.kind == CONTROLLER_INPUT_LEVEL && parsed_kind == PROTOCOL_PARSE_LEVEL && level >= 0);

    /* Check for sensor timeout */
    if (turbidity_ntu < 0 || level < 0) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
    } else if (turbidity_ntu > CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
    } else if (level > CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller->has_valid_level = false;
        controller->has_valid_turbidity = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
    } else {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            /* Turbidity refreshes only turbidity freshness */
            controller_set_safe_idle(controller);
        } else {
            /* Level refreshes only level freshness */
            controller->has_valid_level = true;
            controller->last_level = level;
            controller->last_level_ms = input.now_ms;
            controller_set_safe_idle(controller);
        }
    }

    /* Handle invalid sensor data - go to safe idle state */
    if (input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY || input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
    }

    /* Apply control policy */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        /* No new input - check for timeout */
        if (controller->timed_out || !controller->has_valid_turbidity || !controller->has_valid_level) {
            controller_set_safe_idle(controller);
        } else {
            /* Check for stale data */
            if (controller->last_turbidity_ms + CONTROLLER_SENSOR_TIMEOUT_MS < input.now_ms &&
                controller->has_valid_turbidity && controller->has_valid_level) {
                /* Stale data - safe idle */
                controller_set_safe_idle(controller);
            } else {
                /* Keep current state */
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = false;
            }
        }
    } else {
        /* Handle control actions */

        /* SAFE_IDLE: Always stay in safe idle - no action needed */
        if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_SAFE_IDLE;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
            output.changed = true;
        }

        /* FILTERING: Filter is on, waiting for clear turbidity samples */
        else if (controller->state == CONTROLLER_STATE_FILTERING) {
            /* Count clear streaks while level >= 40 and turbidity <= 35 */
            int current_turbidity = controller->last_turbidity_ntu;
            int current_level = controller->last_level;

            if (current_turbidity > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                /* Turbidity too high - reset clear streak */
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
                output.changed = true;
            } else if (current_level < CONTROLLER_COMPLETE_LEVEL) {
                /* Level too low - still filtering */
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_SETTLING;
                output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
                output.changed = true;
            } else if (current_level >= CONTROLLER_COMPLETE_LEVEL) {
                /* Clear streak achieved - check for settling */
                int clear_streak = controller->clear_streak_count;
                if (clear_streak >= CONTROLLER_CLEAR_STREAK_REQUIRED && current_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Check if we've been settling long enough */
                    uint32_t settle_duration_ms = input.now_ms - controller->settling_started_ms;
                    if (settle_duration_ms >= CONTROLLER_SETTLING_MS) {
                        output.filter_on = false;
                        output.drain_open = true; /* Open drain for draining */
                        output.state = CONTROLLER_STATE_DRAINING;
                        output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                        output.changed = true;
                    } else {
                        /* Settling in progress - stay in FILTERING state but filter is on to reduce turbidity */
                        output.filter_on = true;
                        output.drain_open = false;
                        output.state = CONTROLLER_STATE_FILTERING;
                        output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                        output.changed = true;
                    }
                } else {
                    /* Not enough clear streaks - stay in FILTERING state */
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                    output.changed = true;
                }
            } else {
                /* Level too low - still filtering */
                output.filter_on = true;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                output.changed = true;
            }
        }

        /* SETTLING: Filter is off, drain closed, waiting for clear streaks */
        else if (controller->state == CONTROLLER_STATE_SETTLING) {
            /* Turbidity > 40 resets clear streak and returns to FILTERING */
            int current_turbidity = controller->last_turbidity_ntu;

            if (current_turbidity > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                output.filter_on = true;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                output.changed = true;
            } else {
                /* Valid clear turbidity - drain open after 400ms settling */
                uint32_t settle_duration_ms = input.now_ms - controller->settling_started_ms;
                if (settle_duration_ms >= CONTROLLER_SETTLING_MS) {
                    output.filter_on = false;
                    output.drain_open = true; /* Open drain for draining */
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                    output.changed = true;
                } else {
                    /* Still settling - filter is off, drain closed */
                    output.filter_on = false;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_SETTLING;
                    output.state_name = controller_state_name(CONTROLLER_STATE_SETTLING);
                    output.changed = true;
                }
            }
        }

        /* DRAINING: Drain is open, waiting for disturbances */
        else if (controller->state == CONTROLLER_STATE_DRAINING) {
            int current_turbidity = controller->last_turbidity_ntu;

            /* Turbidity > 50 and level >= 40 closes drain, turns filter on, resets streak */
            if (current_turbidity > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU && current_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                output.filter_on = true;
                output.drain_open = false; /* Close drain */
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = controller_state_name(CONTROLLER_STATE_FILTERING);
                output.changed = true;
            } else if (current_turbidity <= CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
                /* Valid turbidity - drain stays open */
                output.filter_on = false;
                output.drain_open = true;
                output.state = CONTROLLER_STATE_DRAINING;
                output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                output.changed = true;
            } else {
                /* Unknown turbidity - drain stays open */
                output.filter_on = false;
                output.drain_open = true;
                output.state = CONTROLLER_STATE_DRAINING;
                output.state_name = controller_state_name(CONTROLLER_STATE_DRAINING);
                output.changed = true;
            }
        }

        /* COMPLETE: Level below minimum drain threshold */
        else if (controller->state == CONTROLLER_STATE_COMPLETE) {
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_SAFE_IDLE;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
            output.changed = true;
        }

        /* UNKNOWN STATE - go to safe idle */
        else {
            controller_set_safe_idle(controller);
        }
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
        return "STATE SAFE_IDLE";
    default:
        return "STATE UNKNOWN";
    }
}

